#include <bits/stdc++.h>
using namespace std;
int precedence(char op){
    if (op == '^')
        return 3;
    else if (op == '*' || op == '/')
        return 2;
    else if (op == '+' || op == '-')
        return 1;
    else
        return 0;
}
int main(){
    string infix;
    cin >> infix;
    string output;
    stack<char> st;
    for (char c : infix) {
        if (isalnum(c)) {
            output += c;
        } else if (c == '(') {
            st.push(c);
        } else if (c == ')') {
            while (!st.empty() && st.top() != '(') {
                output += st.top();
                st.pop();
            }
            if (!st.empty() && st.top() == '(') {
                st.pop();
            }
        } else {
            while (!st.empty() && st.top() != '(' && precedence(c) <= precedence(st.top())) {
                output += st.top();
                st.pop();
            }
            st.push(c);
        }
    }
    while (!st.empty()) {
        output += st.top();
        st.pop();
    }
    reverse(output.begin(), output.end());
    cout << output;
}
